mapper.select:
select * from t_category
and category_name like concat('%',#{categoryName},'%')
order by create_time desc limit #{start},#{limit};

select *
from t_category
order by id asc;

select b.*
from t_employee a
inner join t_category b on a.category_id = b.id
where a.id = #{empId}
order by b.id asc;
